import { useRef, useState, useEffect, useCallback } from 'react'
import { useVirtualizer } from '@tanstack/react-virtual'
import { Loader } from '@mantine/core'
import { useThumbnailLoader } from '../hooks/useThumbnailLoader'

const MIN_WIDTH = 120
const MAX_WIDTH = 480
const DEFAULT_WIDTH = 220
const ITEM_PADDING = 8
const LABEL_HEIGHT = 20
// DIN A4 portrait aspect ratio (210 × 297 mm)
const PAGE_ASPECT = 297 / 210

interface Props {
  pdfPath: string
  pageCount: number
  selectedPage: number   // 1-indexed
  onSelectPage: (page: number) => void
}

export default function ThumbnailPanel({ pdfPath, pageCount, selectedPage, onSelectPage }: Props) {
  const [panelWidth, setPanelWidth] = useState(DEFAULT_WIDTH)

  const thumbWidth = panelWidth - ITEM_PADDING * 2
  const thumbHeight = Math.round(thumbWidth * PAGE_ASPECT)
  const itemHeight = thumbHeight + LABEL_HEIGHT + ITEM_PADDING * 2

  const scrollRef = useRef<HTMLDivElement>(null)

  const virtualizer = useVirtualizer({
    count: pageCount,
    getScrollElement: () => scrollRef.current,
    estimateSize: () => itemHeight,
    overscan: 3,
  })

  // Re-estimate row heights when panel is resized
  useEffect(() => {
    virtualizer.measure()
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [itemHeight])

  const virtualItems = virtualizer.getVirtualItems()
  const { getSrc, isLoading, invalidate } = useThumbnailLoader(pdfPath, thumbWidth, virtualItems)

  // Scroll selected page into view (e.g. after keyboard navigation)
  useEffect(() => {
    virtualizer.scrollToIndex(selectedPage - 1, { align: 'auto' })
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [selectedPage])

  const handleKeyDown = useCallback((e: React.KeyboardEvent) => {
    if (e.key === 'ArrowLeft' && selectedPage > 1) {
      e.preventDefault()
      onSelectPage(selectedPage - 1)
    } else if (e.key === 'ArrowRight' && selectedPage < pageCount) {
      e.preventDefault()
      onSelectPage(selectedPage + 1)
    }
  }, [selectedPage, pageCount, onSelectPage])

  const startDrag = (e: React.MouseEvent) => {
    const startX = e.clientX
    const startWidth = panelWidth
    const clamp = (w: number) => Math.max(MIN_WIDTH, Math.min(MAX_WIDTH, w))

    const onMove = (ev: MouseEvent) => setPanelWidth(clamp(startWidth + ev.clientX - startX))
    const onUp = (ev: MouseEvent) => {
      setPanelWidth(clamp(startWidth + ev.clientX - startX))
      invalidate()
      document.removeEventListener('mousemove', onMove)
      document.removeEventListener('mouseup', onUp)
    }
    document.addEventListener('mousemove', onMove)
    document.addEventListener('mouseup', onUp)
    e.preventDefault()
  }

  return (
    <div style={{ display: 'flex', height: '100%', flexShrink: 0 }}>
      <div
        ref={scrollRef}
        tabIndex={0}
        onKeyDown={handleKeyDown}
        style={{
          width: panelWidth,
          height: '100%',
          overflowY: 'auto',
          overflowX: 'hidden',
          outline: 'none',
        }}
      >
        <div style={{ height: virtualizer.getTotalSize(), position: 'relative' }}>
          {virtualizer.getVirtualItems().map(item => {
            const page = item.index + 1
            const src = getSrc(page)
            const isSelected = page === selectedPage

            return (
              <div
                key={item.key}
                style={{
                  position: 'absolute',
                  top: item.start,
                  left: 0,
                  width: '100%',
                  height: item.size,
                  padding: ITEM_PADDING,
                  paddingBottom: 0,
                  boxSizing: 'border-box',
                  cursor: 'pointer',
                }}
                onClick={() => onSelectPage(page)}
              >
                <div
                  style={{
                    border: `2px solid ${isSelected ? 'var(--mantine-color-blue-5)' : 'transparent'}`,
                    borderRadius: 4,
                    overflow: 'hidden',
                    background: 'var(--mantine-color-gray-1)',
                  }}
                >
                  {src ? (
                    <img
                      src={src}
                      alt={`Page ${page}`}
                      style={{ width: '100%', display: 'block' }}
                      draggable={false}
                    />
                  ) : (
                    <div
                      style={{
                        width: '100%',
                        height: thumbHeight,
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'center',
                      }}
                    >
                      {isLoading(page) && <Loader size="xs" />}
                    </div>
                  )}
                </div>
                <div
                  style={{
                    textAlign: 'center',
                    fontSize: 11,
                    color: 'var(--mantine-color-dimmed)',
                    height: LABEL_HEIGHT,
                    lineHeight: `${LABEL_HEIGHT}px`,
                  }}
                >
                  {page}
                </div>
              </div>
            )
          })}
        </div>
      </div>

      {/* Resize drag handle */}
      <div
        onMouseDown={startDrag}
        style={{
          width: 4,
          height: '100%',
          cursor: 'col-resize',
          flexShrink: 0,
          background: 'var(--mantine-color-gray-3)',
        }}
      />
    </div>
  )
}

import { useRef, useState, useEffect } from 'react'
import { VirtualItem } from '@tanstack/react-virtual'
import { RenderPage } from '../../wailsjs/go/main/App'

interface ThumbnailLoader {
  getSrc: (page: number) => string | undefined
  isLoading: (page: number) => boolean
  isFailed: (page: number) => boolean
  invalidate: () => void
}

export function useThumbnailLoader(
  pdfPath: string,
  thumbWidth: number,
  virtualItems: VirtualItem[],
): ThumbnailLoader {
  const cacheRef = useRef(new Map<number, string>())
  const loadingRef = useRef(new Set<number>())
  const failedRef = useRef(new Set<number>())
  // Refs don't trigger re-renders; setTick nudges React after mutating them.
  const [, setTick] = useState(0)

  const invalidate = () => {
    cacheRef.current.clear()
    loadingRef.current.clear()
    failedRef.current.clear()
    setTick(t => t + 1)
  }

  // Invalidate when the PDF changes
  useEffect(() => {
    invalidate()
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [pdfPath])

  // Load thumbnails for currently visible items — runs after every render so it
  // picks up new virtual items as the user scrolls without needing a dep array.
  useEffect(() => {
    for (const item of virtualItems) {
      const page = item.index + 1
      if (cacheRef.current.has(page) || loadingRef.current.has(page) || failedRef.current.has(page)) continue
      loadingRef.current.add(page)
      RenderPage(pdfPath, page, thumbWidth)
        .then((b64: string) => {
          cacheRef.current.set(page, `data:image/png;base64,${b64}`)
          loadingRef.current.delete(page)
          setTick(t => t + 1)
        })
        .catch((err: unknown) => {
          console.error(`RenderPage failed for page ${page}:`, err)
          loadingRef.current.delete(page)
          failedRef.current.add(page)
          setTick(t => t + 1)
        })
    }
  })

  return {
    getSrc: (page) => cacheRef.current.get(page),
    isLoading: (page) => loadingRef.current.has(page),
    isFailed: (page) => failedRef.current.has(page),
    invalidate,
  }
}

import { useState } from 'react'
import { Box, Button, Center, Text } from '@mantine/core'
import ThumbnailPanel from './ThumbnailPanel'
import { OpenPDF, PageCount } from '../../wailsjs/go/main/App'

export default function SplitMode() {
  const [pdfPath, setPdfPath] = useState<string | null>(null)
  const [pageCount, setPageCount] = useState(0)
  const [selectedPage, setSelectedPage] = useState(1)

  const handleOpen = async () => {
    const path = await OpenPDF()
    if (!path) return
    const count = await PageCount(path)
    setPdfPath(path)
    setPageCount(count)
    setSelectedPage(1)
  }

  return (
    <Box style={{ display: 'flex', height: '100%' }}>
      {pdfPath ? (
        <ThumbnailPanel
          pdfPath={pdfPath}
          pageCount={pageCount}
          selectedPage={selectedPage}
          onSelectPage={setSelectedPage}
        />
      ) : null}

      <Box style={{ flex: 1, overflow: 'hidden', display: 'flex', flexDirection: 'column' }}>
        {pdfPath ? (
          <Center style={{ height: '100%' }}>
            <Text c="dimmed" size="sm">Page {selectedPage} of {pageCount}</Text>
          </Center>
        ) : (
          <Center style={{ height: '100%' }}>
            <Button onClick={handleOpen}>Open PDF</Button>
          </Center>
        )}
      </Box>
    </Box>
  )
}

package main

import (
	"context"
	"encoding/base64"
	"fmt"
	"os"
	"os/exec"
	"path/filepath"
	"strconv"

	"github.com/wailsapp/wails/v2/pkg/runtime"
)

// App struct
type App struct {
	ctx context.Context
}

// NewApp creates a new App application struct
func NewApp() *App {
	return &App{}
}

// startup is called when the app starts. The context is saved
// so we can call the runtime methods
func (a *App) startup(ctx context.Context) {
	a.ctx = ctx
}

// OpenPDF shows a file-open dialog filtered to PDFs and returns the selected path.
// Returns an empty string if the user cancels.
func (a *App) OpenPDF() (string, error) {
	path, err := runtime.OpenFileDialog(a.ctx, runtime.OpenDialogOptions{
		Title: "Open PDF",
		Filters: []runtime.FileFilter{
			{DisplayName: "PDF Files (*.pdf)", Pattern: "*.pdf"},
		},
	})
	return path, err
}

// PageCount returns the number of pages in the PDF at path.
func (a *App) PageCount(path string) (int, error) {
	return pdfPageCount(path)
}

// RenderPage renders a single page of the PDF at path as a PNG and returns it
// base64-encoded. widthPx controls the output width; height is scaled proportionally.
func (a *App) RenderPage(path string, pageNum int, widthPx int) (string, error) {
	tmpDir, err := os.MkdirTemp("", "psp-render-*")
	if err != nil {
		return "", err
	}
	defer os.RemoveAll(tmpDir)

	outPrefix := filepath.Join(tmpDir, "page")
	page := strconv.Itoa(pageNum)

	out, err := exec.Command(
		"pdftoppm",
		"-f", page,
		"-l", page,
		"-singlefile",
		"-png",
		"-scale-to-x", strconv.Itoa(widthPx),
		"-scale-to-y", "-1",
		path,
		outPrefix,
	).CombinedOutput()
	if err != nil {
		return "", fmt.Errorf("pdftoppm: %w\n%s", err, out)
	}

	data, err := os.ReadFile(outPrefix + ".png")
	if err != nil {
		return "", err
	}
	return base64.StdEncoding.EncodeToString(data), nil
}

